# In a Parameter Execute DAT watching a COMP's custom parameters

def onValueChange(par, prev):
	"""Called when a parameter value changes."""
	if par.name == 'Speed':
		# Update animation speed
		op('animation_comp').par.speed = par.eval()

	elif par.name == 'Color':
		# Update color across multiple operators
		for top in parent().findChildren(type=TOP):
			if hasattr(top.par, 'colorr'):
				top.par.colorr = par.eval()[0]
				top.par.colorg = par.eval()[1]
				top.par.colorb = par.eval()[2]


def onPulse(par):
	"""Called when a pulse parameter is pushed."""
	if par.name == 'Reset':
		parent().ext.MyExt.Reset()
	elif par.name == 'Randomize':
		import random
		parent().par.Speed = random.uniform(0.1, 2.0)

# In an extension class, handle parameter changes directly

class MyControlExt:
	def __init__(self, ownerComp):
		self.ownerComp = ownerComp

	def onParValueChange(self, par, prev):
		"""Called automatically if extension is registered for callbacks."""
		if par.name == 'Brightness':
			op('level1').par.brightness1 = par.eval()
		elif par.name == 'Active':
			op('switch1').par.index = 1 if par.eval() else 0
